/**
 * MMS Base Service
 *
 * Abstract base class for all domain services in the MMS system.
 * Provides consistent patterns for:
 * - OpenTelemetry distributed tracing
 * - Structured logging with Pino
 * - Database transaction management
 * - Error handling and propagation
 *
 * All domain services (Ingestion, Fleet, PM Scheduler, etc.) extend this base.
 *
 * @see specs/004-domain-services.md
 */

import type { Logger } from 'pino';
import type { Span, Attributes } from '@opentelemetry/api';
import { createChildLogger, logError as pinoLogError } from '../logging/logger';
import { db, withTransaction, type Transaction, type Database } from '../db/connection';
import {
  withSpan,
  withSpanSync,
  getTracer,
  getTraceContext,
  recordSpanError,
  addSpanEvent,
  MmsAttributes,
  SpanKind,
  type Tracer,
} from '../tracing';
import { MmsError, toMmsError } from '../errors';

/**
 * Service configuration options
 */
export interface ServiceConfig {
  /** Service name for tracing and logging */
  name: string;
  /** Service version */
  version?: string;
  /** Additional context for all logs and spans */
  context?: Record<string, unknown>;
}

/**
 * Operation result wrapper for consistent return types
 */
export interface OperationResult<T> {
  success: boolean;
  data?: T;
  error?: MmsError;
  durationMs: number;
}

/**
 * Base service class for all MMS domain services
 *
 * @example
 * ```typescript
 * class FleetService extends BaseService {
 *   constructor() {
 *     super({ name: 'fleet-service' });
 *   }
 *
 *   async getTrains(fleetId: string): Promise<Train[]> {
 *     return this.traced('getTrains', async (span) => {
 *       span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
 *       return this.db.query.trains.findMany({
 *         where: eq(trains.fleetId, fleetId)
 *       });
 *     });
 *   }
 * }
 * ```
 */
export abstract class BaseService {
  protected readonly serviceName: string;
  protected readonly log: Logger;
  protected readonly tracer: Tracer;
  protected readonly db: Database;

  constructor(config: ServiceConfig) {
    this.serviceName = config.name;
    this.log = createChildLogger({
      service: config.name,
      version: config.version ?? '0.1.0',
      ...config.context,
    });
    this.tracer = getTracer(config.name);
    this.db = db;
  }

  /**
   * Execute an async operation with tracing
   *
   * Automatically creates a span, records errors, and measures duration.
   * Propagates trace context for distributed tracing.
   *
   * @param operationName - Name of the operation (becomes span name)
   * @param fn - Async function to execute

 * - Service pattern analysis
 *
 * @see specs/004-domain-services.md Section 4.3
 */
export const runAssignments = pgTable(
  'run_assignments',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    routeId: uuid('route_id')
      .notNull()
      .references(() => routes.id),
    assignmentDate: date('assignment_date').notNull(),

    // Optimizer run context
    requestId: uuid('request_id').notNull(), // Groups assignments from same optimizer run
    optimizerStatus: optimizerStatusEnum('optimizer_status').notNull(),
    score: decimal('score', { precision: 10, scale: 4 }), // Assignment quality score

    // Explanation data (stored as JSON for flexibility)
    explanation: text('explanation'), // JSON array of ExplanationTrace

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    // Primary query: Find recent assignments for a train to determine typical route
    index('idx_run_assignments_train_date').on(table.trainId, table.assignmentDate),
    // Find all assignments for a specific date (for daily operations view)
    index('idx_run_assignments_date').on(table.assignmentDate),
    // Group assignments by optimizer run
    index('idx_run_assignments_request').on(table.requestId),
    // Route-centric queries (route utilization analysis)
    index('idx_run_assignments_route_date').on(table.routeId, table.assignmentDate),
    // Unique constraint: one assignment per train per day
    uniqueIndex('idx_run_assignments_unique').on(table.trainId, table.assignmentDate),
  ]
);

export const runAssignmentsRelations = relations(runAssignments, ({ one }) => ({
  train: one(trains, {
    fields: [runAssignments.trainId],
    references: [trains.id],
  }),
  route: one(routes, {
    fields: [runAssignments.routeId],
    references: [routes.id],
  }),
}));

