 *
 * OCC is the train dispatch center that operators use to manage daily
 * fleet operations. MMS provides optimized run assignments; OCC returns
 * actual mileage data for variance tracking and projection accuracy.
 *
 * Delivery methods:
 * - SFTP: File drop to configured server (primary production method)
 * - REST API: Push to OCC webhook endpoint (alternative)
 *
 * @see specs/007-integration.md Section 7.5
 */

import { eq, and, gte, lte, desc, sql, type SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  runAssignments,
  trains,
  routes,
  depots,
  type RunAssignment,
  type Train,
  type Route,
} from '../lib/db/schema';
import { withRetry, EXTERNAL_SERVICE_RETRY_CONFIG } from '../lib/utils/resilience';
import { ValidationError, ExternalServiceError } from '../lib/errors';
import { v4 as uuid } from 'uuid';

// =============================================================================
// Types
// =============================================================================

/**
 * OCC export file format (CSV row structure)
 */
export interface OCCRunAssignmentRow {
  date: string;
  train_number: string;
  route_code: string;
  depot_start: string;
  depot_end: string;
  start_time: string;
  end_time: string;
}

/**
 * OCC mileage feedback from operations
 */
export interface OCCMileageFeedback {
  date: string;
  trainNumber: string;
  routeCode: string;
  actualKm: number;
  scheduledKm: number;
  variance: number;
  notes?: string;
}

/**
 * Export job status
 */
export type ExportStatus = 'PENDING' | 'PROCESSING' | 'COMPLETED' | 'FAILED';

/**
 * Export delivery method
 */
export type DeliveryMethod = 'SFTP' | 'REST' | 'LOCAL';

/**
 * Export job metadata
 */
export interface ExportJob {
  id: string;
  exportDate: string;
  status: ExportStatus;
  deliveryMethod: DeliveryMethod;
  recordCount: number;
  filePath?: string;
  deliveredAt?: Date;
  errorMessage?: string;
  createdAt: Date;
  completedAt?: Date;
}

/**
 * Export request parameters
 */
export interface ExportRequest {
  date: string;
  fleetId?: string;
  deliveryMethod?: DeliveryMethod;
  destinationUrl?: string;
}

/**
 * Export result
 */
export interface ExportResult {
  jobId: string;
  status: ExportStatus;
  recordCount: number;
  csvContent?: string;
  filePath?: string;
  deliveredAt?: Date;
  errorMessage?: string;
}

/**
 * Mileage feedback processing result
 */
export interface FeedbackResult {
  processed: number;
  valid: number;
  invalid: number;
  errors: FeedbackError[];
  varianceSummary: VarianceSummary;
}

/**
 * Feedback validation error
 */
export interface FeedbackError {
  row: number;
  trainNumber: string;
  field: string;
  message: string;
}

/**
 * Variance summary statistics
 */
export interface VarianceSummary {
  avgVarianceKm: number;
  maxVarianceKm: number;
  minVarianceKm: number;
  totalScheduledKm: number;
  totalActualKm: number;
  trainsWithVariance: number;
}

/**
 * SFTP configuration for file delivery
 */
export interface SftpConfig {
  host: string;
  port: number;
  username: string;
  privateKey?: string;
  password?: string;
  remotePath: string;
}

// =============================================================================
// In-Memory Storage (production: would use database)
// =============================================================================

const exportJobs = new Map<string, ExportJob>();
const feedbackRecords: OCCMileageFeedback[] = [];

// =============================================================================
// Service Implementation
// =============================================================================

/**
 * OCC Integration Service
 *
 * Manages bidirectional data flow between MMS and Operations Control Center:
 * - Exports daily run assignments (MMS → OCC)
 * - Receives actual mileage feedback (OCC → MMS)
 */
class OCCService extends BaseService {
  private static instance: OCCService | null = null;

  private constructor() {
    super({ name: 'occ-service' });
  }

  /**
   * Get singleton instance
   */
  static getInstance(): OCCService {
    if (!OCCService.instance) {
      OCCService.instance = new OCCService();
    }
    return OCCService.instance;
  }

  /**
   * Reset singleton (for testing)
   */
  static resetInstance(): void {
    OCCService.instance = null;
    exportJobs.clear();
    feedbackRecords.length = 0;
  }

  // ===========================================================================
  // Run Assignment Export
  // ===========================================================================

  /**
   * Export run assignments for a given date to OCC format
   *
   * Generates CSV with columns:
   * date, train_number, route_code, depot_start, depot_end, start_time, end_time
   *
   * @param request Export parameters (date, optional fleet filter, delivery method)
   * @returns Export result with job ID and status
   */
  async exportRunAssignments(request: ExportRequest): Promise<ExportResult> {
    return this.traced('exportRunAssignments', async (span) => {
      span.setAttribute(MmsAttributes.EXPORT_DATE, request.date);
      if (request.fleetId) {
        span.setAttribute(MmsAttributes.FLEET_ID, request.fleetId);
      }

      const jobId = uuid();
      const deliveryMethod = request.deliveryMethod ?? 'LOCAL';

      // Create job record
      const job: ExportJob = {
        id: jobId,
        exportDate: request.date,
        status: 'PROCESSING',
        deliveryMethod,
        recordCount: 0,
        createdAt: new Date(),
      };
      exportJobs.set(jobId, job);

      try {
        // Fetch run assignments with related data
        const assignments = await this.fetchAssignmentsForDate(request.date, request.fleetId);
        span.setAttribute('mms.record_count', assignments.length);

        if (assignments.length === 0) {
          this.log.warn({ date: request.date }, 'No run assignments found for export date');
        }

        // Generate CSV content
        const csvContent = this.generateCsvContent(assignments);
        job.recordCount = assignments.length;

        // Deliver based on method
        switch (deliveryMethod) {
          case 'SFTP':
            await this.deliverViaSftp(csvContent, request.date, request.destinationUrl);
            job.deliveredAt = new Date();
            break;

          case 'REST':
            await this.deliverViaRest(csvContent, request.destinationUrl);
            job.deliveredAt = new Date();
            break;

          case 'LOCAL':
          default:
            job.filePath = `exports/occ_run_assignments_${request.date}.csv`;
            break;
        }

        job.status = 'COMPLETED';
        job.completedAt = new Date();
        exportJobs.set(jobId, job);

        this.log.info(
          {
            jobId,
            date: request.date,
            recordCount: assignments.length,
            deliveryMethod,
          },
          'Run assignment export completed'
        );

        return {
          jobId,
          status: 'COMPLETED',
          recordCount: assignments.length,
          csvContent: deliveryMethod === 'LOCAL' ? csvContent : undefined,
          filePath: job.filePath,
          deliveredAt: job.deliveredAt,
        };
      } catch (error) {
        job.status = 'FAILED';
        job.errorMessage = error instanceof Error ? error.message : 'Unknown error';
        job.completedAt = new Date();
        exportJobs.set(jobId, job);

        this.log.error({ jobId, error }, 'Run assignment export failed');

        throw new ExternalServiceError(
          'OCC',
          `Export failed: ${job.errorMessage}`,
          error instanceof Error ? error : undefined
        );
      }
    });
  }

  /**
   * Fetch run assignments for a specific date with train and route details
   */
  private async fetchAssignmentsForDate(
    date: string,
    fleetId?: string
  ): Promise<
    Array<{
      assignment: RunAssignment;
      train: Train;
      route: Route;
      depot: { code: string } | null;
    }>
  > {
    // Build query with joins
    const results = await this.db
      .select({
        assignment: runAssignments,
        train: trains,
        route: routes,
        depot: {
          code: depots.code,
        },
      })
      .from(runAssignments)
      .innerJoin(trains, eq(runAssignments.trainId, trains.id))
      .innerJoin(routes, eq(runAssignments.routeId, routes.id))
      .leftJoin(depots, eq(trains.homeDepotId, depots.id))
      .where(
        and(
          eq(runAssignments.assignmentDate, date),
          fleetId ? eq(trains.fleetId, fleetId) : undefined
        )
      )
      .orderBy(trains.trainNumber);

    return results;
  }

  /**
   * Generate CSV content in OCC format
   */
  private generateCsvContent(
    assignments: Array<{
      assignment: RunAssignment;
      train: Train;
      route: Route;
      depot: { code: string } | null;
    }>
  ): string {
    const header = 'date,train_number,route_code,depot_start,depot_end,start_time,end_time';
    const rows = assignments.map((a) => {
      const depotCode = a.depot?.code ?? 'UNK';
      // Standard service hours (would come from route config in production)
      const startTime = '05:30';
      const endTime = '23:30';

      return [
        a.assignment.assignmentDate,
        a.train.trainNumber,
        a.route.routeCode,
        depotCode,
        depotCode, // Same depot for start/end (would be calculated in production)
        startTime,
        endTime,
      ].join(',');
    });

    return [header, ...rows].join('\n');
  }

  /**
   * Deliver CSV via SFTP
   * (Stub implementation - would use ssh2-sftp-client in production)
   */
  private async deliverViaSftp(
    csvContent: string,
    date: string,
    _destinationUrl?: string
  ): Promise<void> {
    return withRetry(
      async () => {
        // In production: use ssh2-sftp-client
        // const sftp = new SFTPClient();
        // await sftp.connect(config);
        // await sftp.put(Buffer.from(csvContent), remotePath);
        // await sftp.end();

        this.log.info(
          {
            date,
            contentLength: csvContent.length,
          },
          'SFTP delivery would occur here (stub)'
        );
      },
      { ...EXTERNAL_SERVICE_RETRY_CONFIG, context: 'SFTP delivery' }
    );
  }

  /**
   * Deliver CSV via REST API POST
   * (Stub implementation - would use fetch in production)
   */
  private async deliverViaRest(csvContent: string, destinationUrl?: string): Promise<void> {
    return withRetry(
      async () => {
        if (!destinationUrl) {
          throw new ValidationError('Destination URL required for REST delivery');
        }

        // In production: use fetch to POST CSV
        // await fetch(destinationUrl, {
        //   method: 'POST',
        //   headers: { 'Content-Type': 'text/csv' },
        //   body: csvContent,
        // });

        this.log.info(
          {
            url: destinationUrl,
            contentLength: csvContent.length,
          },
          'REST delivery would occur here (stub)'
        );
      },
      { ...EXTERNAL_SERVICE_RETRY_CONFIG, context: 'REST delivery' }
    );
  }

  // ===========================================================================
  // Mileage Feedback
  // ===========================================================================

  /**
   * Process mileage feedback from OCC
   *
   * Validates and stores actual mileage data for variance analysis.
   * Used to improve projection accuracy and identify operational anomalies.
   *
   * @param feedback Array of mileage feedback records from OCC
   * @returns Processing result with validation errors and variance summary
   */
  async processMileageFeedback(feedback: OCCMileageFeedback[]): Promise<FeedbackResult> {
    return this.traced('processMileageFeedback', async (span) => {
      span.setAttribute('mms.feedback_count', feedback.length);

      const errors: FeedbackError[] = [];
      const validRecords: OCCMileageFeedback[] = [];

      // Validate each record
      for (let i = 0; i < feedback.length; i++) {
        const record = feedback[i];
        if (!record) continue;

        const rowErrors = await this.validateFeedbackRecord(record, i + 1);

        if (rowErrors.length > 0) {
          errors.push(...rowErrors);
        } else {
          // Calculate variance if not provided
          if (record.variance === undefined && record.actualKm !== undefined) {
            record.variance = record.actualKm - record.scheduledKm;
          }
          validRecords.push(record);
        }
      }

      // Store valid records
      feedbackRecords.push(...validRecords);

      // Calculate variance summary
      const varianceSummary = this.calculateVarianceSummary(validRecords);

      // Log significant variance
      if (Math.abs(varianceSummary.avgVarianceKm) > 50) {
        this.log.warn(
          {
            avgVariance: varianceSummary.avgVarianceKm,
            maxVariance: varianceSummary.maxVarianceKm,
            trainsAffected: varianceSummary.trainsWithVariance,
          },
          'Significant mileage variance detected'
        );
      }

      this.log.info(
        {
          processed: feedback.length,
          valid: validRecords.length,
          invalid: errors.length,
          avgVarianceKm: varianceSummary.avgVarianceKm,
        },
        'Mileage feedback processed'
      );

      return {
        processed: feedback.length,
        valid: validRecords.length,
        invalid: errors.length,
        errors,
        varianceSummary,
      };
    });
  }

  /**
   * Validate a single feedback record
   */
  private async validateFeedbackRecord(
    record: OCCMileageFeedback,
    row: number
  ): Promise<FeedbackError[]> {
    const errors: FeedbackError[] = [];

    // Required fields
    if (!record.date) {
      errors.push({ row, trainNumber: record.trainNumber ?? '', field: 'date', message: 'Date is required' });
    }

    if (!record.trainNumber) {
      errors.push({ row, trainNumber: '', field: 'trainNumber', message: 'Train number is required' });
    }

    if (record.actualKm === undefined || record.actualKm === null) {
      errors.push({ row, trainNumber: record.trainNumber ?? '', field: 'actualKm', message: 'Actual km is required' });
    }

    // Value validation
    if (record.actualKm !== undefined && record.actualKm < 0) {
      errors.push({ row, trainNumber: record.trainNumber, field: 'actualKm', message: 'Actual km cannot be negative' });
    }

    if (record.scheduledKm !== undefined && record.scheduledKm < 0) {
      errors.push({
        row,
        trainNumber: record.trainNumber,
        field: 'scheduledKm',
        message: 'Scheduled km cannot be negative',
      });
    }

    // Date format validation (YYYY-MM-DD)
    if (record.date && !/^\d{4}-\d{2}-\d{2}$/.test(record.date)) {
      errors.push({
        row,
        trainNumber: record.trainNumber,
        field: 'date',
        message: 'Date must be in YYYY-MM-DD format',
      });
    }

    // Train existence check
    if (record.trainNumber && errors.length === 0) {
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.trainNumber, record.trainNumber),
      });

      if (!train) {
        errors.push({
          row,
          trainNumber: record.trainNumber,
          field: 'trainNumber',
          message: `Unknown train number: ${record.trainNumber}`,
        });
      }
    }

    return errors;
  }

  /**
   * Calculate variance statistics from feedback records
   */
  private calculateVarianceSummary(records: OCCMileageFeedback[]): VarianceSummary {
    if (records.length === 0) {
      return {
        avgVarianceKm: 0,
        maxVarianceKm: 0,
        minVarianceKm: 0,
        totalScheduledKm: 0,
        totalActualKm: 0,
        trainsWithVariance: 0,
      };
    }

    const variances = records.map((r) => r.variance);
    const totalScheduled = records.reduce((sum, r) => sum + (r.scheduledKm || 0), 0);
    const totalActual = records.reduce((sum, r) => sum + (r.actualKm || 0), 0);
    const trainsWithVariance = records.filter((r) => Math.abs(r.variance) > 10).length;

    return {
      avgVarianceKm: variances.reduce((sum, v) => sum + v, 0) / variances.length,
      maxVarianceKm: Math.max(...variances),
      minVarianceKm: Math.min(...variances),
      totalScheduledKm: totalScheduled,
      totalActualKm: totalActual,
      trainsWithVariance,
    };
  }

  // ===========================================================================
  // Export History
  // ===========================================================================

  /**
   * Get export job by ID
   */
  async getExportJob(jobId: string): Promise<ExportJob | null> {
    return this.traced('getExportJob', async (span) => {
      span.setAttribute('mms.job_id', jobId);
      return exportJobs.get(jobId) ?? null;
    });
  }

  /**
   * Get export history with optional date range filter
   */
  async getExportHistory(options?: {
    fromDate?: string;
    toDate?: string;
    status?: ExportStatus;
    limit?: number;
  }): Promise<ExportJob[]> {
    return this.traced('getExportHistory', async (span) => {
      let jobs = Array.from(exportJobs.values());

      if (options?.fromDate) {
        jobs = jobs.filter((j) => j.exportDate >= options.fromDate!);
      }

      if (options?.toDate) {
        jobs = jobs.filter((j) => j.exportDate <= options.toDate!);
      }

      if (options?.status) {
        jobs = jobs.filter((j) => j.status === options.status);
      }

      // Sort by creation date descending
      jobs.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());

      // Apply limit
      if (options?.limit) {
        jobs = jobs.slice(0, options.limit);
      }

      span.setAttribute('mms.result_count', jobs.length);
      return jobs;
    });
  }

  /**
   * Get mileage feedback for variance analysis
   */
  async getMileageFeedback(options?: {
    trainNumber?: string;
    fromDate?: string;
    toDate?: string;
    minVariance?: number;
  }): Promise<OCCMileageFeedback[]> {
    return this.traced('getMileageFeedback', async (span) => {
      let records = [...feedbackRecords];

      if (options?.trainNumber) {
        records = records.filter((r) => r.trainNumber === options.trainNumber);
      }

      if (options?.fromDate) {
        records = records.filter((r) => r.date >= options.fromDate!);
      }

      if (options?.toDate) {
        records = records.filter((r) => r.date <= options.toDate!);
      }

      if (options?.minVariance !== undefined) {
        records = records.filter((r) => Math.abs(r.variance) >= options.minVariance!);
      }

      span.setAttribute('mms.result_count', records.length);
      return records;
    });
  }
}

// =============================================================================
// Exports
// =============================================================================

export const occService = OCCService.getInstance();

// Export class for testing
export { OCCService };

