          deliveryMethod: job.deliveryMethod,
          recordCount: job.recordCount,
          filePath: job.filePath,
          deliveredAt: job.deliveredAt?.toISOString(),
          errorMessage: job.errorMessage,
          createdAt: job.createdAt.toISOString(),
          completedAt: job.completedAt?.toISOString(),
        },
        requestId
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to retrieve export job';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /occ/feedback
 *
 * Query stored mileage feedback records.
 *
 * Query Parameters:
 * - trainNumber: Filter by train number
 * - fromDate: Filter by date >= value (YYYY-MM-DD)
 * - toDate: Filter by date <= value (YYYY-MM-DD)
 * - minVariance: Filter by |variance| >= value (km)
 *
 * @example
 * GET /occ/feedback?trainNumber=1001&minVariance=50
 */
occRoutes.get('/occ/feedback', async (c) => {
  const requestId = getRequestId(c);

  try {
    const trainNumber = c.req.query('trainNumber');
    const fromDate = c.req.query('fromDate');
    const toDate = c.req.query('toDate');
    const minVarianceStr = c.req.query('minVariance');
    const minVariance = minVarianceStr ? parseFloat(minVarianceStr) : undefined;

    const feedback = await occService.getMileageFeedback({
      trainNumber,
      fromDate,
      toDate,
      minVariance,
    });

    return c.json(
      success(
        {
          feedback,
          count: feedback.length,
        },
        requestId
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to retrieve feedback';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /occ/download/:jobId
 *
 * Download the CSV file for a completed export job.
 *
 * Returns:
 * - 200 OK with CSV content (Content-Type: text/csv)
 * - 404 Not Found if job doesn't exist
 * - 400 Bad Request if job is not completed
 */
occRoutes.get('/occ/download/:jobId', async (c) => {
  const requestId = getRequestId(c);
  const jobId = c.req.param('jobId');

  try {
    const job = await occService.getExportJob(jobId);

    if (!job) {
      return c.json(error(ErrorCodes.NOT_FOUND, 'Export job not found', requestId, { jobId }), 404);
    }

    if (job.status !== 'COMPLETED') {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Export job is not completed', requestId, {
          jobId,
          status: job.status,
        }),
        400
      );
    }

    // For LOCAL delivery method, we would read the file from disk
    // For now, we'll need to re-export to get the content
    // In production, CSV content would be stored or retrieved from file system

    // Re-export to get CSV (simplified approach)
    const result = await occService.exportRunAssignments({
      date: job.exportDate,
      deliveryMethod: 'LOCAL',
    });

    c.header('Content-Type', 'text/csv');
    c.header('Content-Disposition', `attachment; filename="occ_run_assignments_${job.exportDate}.csv"`);

    return c.body(result.csvContent ?? '');
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Download failed';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

