/**
 * MMS OpenTelemetry Tracing Configuration
 *
 * Provides distributed tracing for all MMS services.
 * Integrates with Pino logging for correlated trace context.
 *
 * Features:
 * - Automatic span context propagation
 * - Span attribute helpers for domain-specific data
 * - Integration with existing Pino logger
 * - Configurable exporters (OTLP, Jaeger, Console)
 *
 * @see specs/004-domain-services.md - All services emit OpenTelemetry traces
 */

import {
  trace,
  context,
  SpanStatusCode,
  SpanKind,
  type Span,
  type Tracer,
  type Context,
  type SpanOptions,
  type Attributes,
} from '@opentelemetry/api';
import {
  SEMRESATTRS_SERVICE_NAME,
  SEMRESATTRS_SERVICE_VERSION,
  SEMRESATTRS_DEPLOYMENT_ENVIRONMENT,
} from '@opentelemetry/semantic-conventions';

const SERVICE_NAME = process.env['SERVICE_NAME'] ?? 'mms';
const SERVICE_VERSION = process.env['SERVICE_VERSION'] ?? '0.1.0';
const ENVIRONMENT = process.env['NODE_ENV'] ?? 'development';

/**
 * Domain-specific span attributes for MMS
 */
export const MmsAttributes = {
  // Train attributes
  TRAIN_ID: 'mms.train.id',
  TRAIN_NUMBER: 'mms.train.number',
  FLEET_ID: 'mms.fleet.id',

  // PM attributes
  PM_SCHEDULE_ID: 'mms.pm.schedule_id',
  PM_TYPE_CODE: 'mms.pm.type_code',
  PM_STATUS: 'mms.pm.status',

  // Depot attributes
  DEPOT_ID: 'mms.depot.id',
  DEPOT_CODE: 'mms.depot.code',

  // Mileage attributes
  MILEAGE_KM: 'mms.mileage.km',
  DAILY_KM: 'mms.mileage.daily_km',

  // Ingestion attributes
  INGESTION_FILE: 'mms.ingestion.file',
  INGESTION_JOB_ID: 'mms.ingestion.job_id',
  INGESTION_RECORD_COUNT: 'mms.ingestion.record_count',
  INGESTION_RECORDS: 'mms.ingestion.records',
  INGESTION_VALID: 'mms.ingestion.valid',
  INGESTION_INVALID: 'mms.ingestion.invalid',

  // Optimizer attributes
  OPTIMIZER_JOB_ID: 'mms.optimizer.job_id',
  OPTIMIZER_SOLVER: 'mms.optimizer.solver',
  OPTIMIZER_SOLVE_TIME_MS: 'mms.optimizer.solve_time_ms',
  OPTIMIZER_OBJECTIVE: 'mms.optimizer.objective',
  OPTIMIZER_STATUS: 'mms.optimizer.status',

  // Baseline attributes
  BASELINE_ID: 'mms.baseline.id',
  BASELINE_VERSION: 'mms.baseline.version',

  // Scenario attributes
  SCENARIO_ID: 'mms.scenario.id',
  SCENARIO_NAME: 'mms.scenario.name',

  // Queue attributes
  QUEUE_NAME: 'mms.queue.name',
  JOB_ID: 'mms.job.id',
  JOB_ATTEMPT: 'mms.job.attempt',

  // User attributes
  USER_ID: 'mms.user.id',
  USER_EMAIL: 'mms.user.email',

  // Database attributes
  DB_OPERATION: 'mms.db.operation',
  DB_TABLE: 'mms.db.table',
  DB_ROWS_AFFECTED: 'mms.db.rows_affected',

  // Error attributes
  ERROR_CODE: 'mms.error.code',
  ERROR_TYPE: 'mms.error.type',
} as const;

/**
 * MMS Resilience Utilities
 *
 * Provides retry and circuit breaker patterns for handling transient failures.
 * Critical for integration with external systems (Maximo, OCC) and for
 * maintaining service availability during infrastructure issues.
 *
 * @see specs/007-integration.md - External system integration patterns
 * @see specs/004-domain-services.md - Service reliability requirements
 */

import { withSpan, addSpanEvent, SpanKind } from '../tracing';
import { TimeoutError, ExternalServiceError, ServiceUnavailableError } from '../errors';
import { logger } from '../logging/logger';

// =============================================================================
// Retry Configuration & Implementation
// =============================================================================

/**
 * Retry configuration options
 */
export interface RetryConfig {
  /** Maximum number of retry attempts */
  maxAttempts: number;
  /** Initial delay between retries (ms) */
  initialDelayMs: number;
  /** Maximum delay between retries (ms) */
  maxDelayMs: number;
  /** Backoff multiplier (e.g., 2 for exponential) */
  backoffMultiplier: number;
  /** Add random jitter to delays (prevents thundering herd) */
  jitter: boolean;
  /** Predicate to determine if an error is retryable */
  isRetryable?: (error: unknown) => boolean;
  /** Callback invoked before each retry */
  onRetry?: (error: unknown, attempt: number, delayMs: number) => void;
}

/**
 * Default retry configuration
 * Suitable for most transient failure scenarios
 */
export const DEFAULT_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 3,
  initialDelayMs: 1000,
  maxDelayMs: 30000,
  backoffMultiplier: 2,
  jitter: true,
  isRetryable: defaultIsRetryable,
};

/**
 * Aggressive retry configuration
 * Use for critical operations that must succeed
 */
export const AGGRESSIVE_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 5,
  initialDelayMs: 500,
  maxDelayMs: 60000,
  backoffMultiplier: 2,
  jitter: true,
  isRetryable: defaultIsRetryable,
};

/**
 * Quick retry configuration
 * Use for fast operations where quick recovery is expected
 */
export const QUICK_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 3,
  initialDelayMs: 100,
  maxDelayMs: 2000,
  backoffMultiplier: 2,
  jitter: true,
  isRetryable: defaultIsRetryable,
};

/**
 * External service retry configuration

