/**
 * OCC Integration Routes
 *
 * REST endpoints for Operations Control Center integration:
 * - Export run assignments (MMS → OCC)
 * - Receive mileage feedback (OCC → MMS)
 * - Export job history
 *
 * Key endpoints:
 * - POST /occ/export-assignments - Export daily run assignments as CSV
 * - POST /occ/mileage-feedback - Receive actual mileage data from OCC
 * - GET /occ/export-history - List export job history
 * - GET /occ/export/:jobId - Get specific export job status
 * - GET /occ/feedback - Query mileage feedback records
 *
 * @see specs/007-integration.md Section 7.5
 */

import { Hono } from 'hono';
import {
  success,
  error,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  occService,
  type ExportRequest,
  type OCCMileageFeedback,
  type ExportStatus,
} from '../../services/occ';

export const occRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * POST /occ/export-assignments
 *
 * Export run assignments for a given date to OCC CSV format.
 *
 * Request Body:
 * - date: Assignment date (YYYY-MM-DD) [required]
 * - fleetId: Optional fleet filter
 * - deliveryMethod: 'LOCAL' | 'SFTP' | 'REST' (default: LOCAL)
 * - destinationUrl: Required for SFTP/REST delivery
 *
 * Returns:
 * - 200 OK for LOCAL delivery with CSV content
 * - 202 Accepted for SFTP/REST delivery (async)
 * - 400 Bad Request for validation errors
 *
 * @example
 * POST /occ/export-assignments
 * {
 *   "date": "2026-01-15",
 *   "deliveryMethod": "LOCAL"
 * }
 */
occRoutes.post('/occ/export-assignments', async (c) => {
  const requestId = getRequestId(c);

  try {
    const body = await c.req.json();

    // Validate required fields
    if (!body.date) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'date is required', requestId, {
          field: 'date',
          expected: 'YYYY-MM-DD format',
        }),
        400
      );
    }

    // Validate date format
    if (!/^\d{4}-\d{2}-\d{2}$/.test(body.date)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid date format', requestId, {
          field: 'date',
          expected: 'YYYY-MM-DD',
          received: body.date,
        }),
        400
      );
    }

    // Validate delivery method if provided
    const validMethods = ['LOCAL', 'SFTP', 'REST'];
    if (body.deliveryMethod && !validMethods.includes(body.deliveryMethod)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid delivery method', requestId, {
          field: 'deliveryMethod',
          expected: validMethods,
          received: body.deliveryMethod,
        }),
        400
      );
    }

    // Validate destinationUrl for SFTP/REST
    if ((body.deliveryMethod === 'SFTP' || body.deliveryMethod === 'REST') && !body.destinationUrl) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'destinationUrl is required for SFTP/REST delivery', requestId, {
          field: 'destinationUrl',
        }),
        400
      );
    }

    const request: ExportRequest = {
      date: body.date,
      fleetId: body.fleetId,
      deliveryMethod: body.deliveryMethod ?? 'LOCAL',
      destinationUrl: body.destinationUrl,
    };

    const result = await occService.exportRunAssignments(request);

    // For async delivery methods, return 202 Accepted
    if (request.deliveryMethod === 'SFTP' || request.deliveryMethod === 'REST') {
      return c.json(
        success(
          {
            jobId: result.jobId,
            status: result.status,
            recordCount: result.recordCount,
            deliveredAt: result.deliveredAt?.toISOString(),
          },
          { timing: { durationMs: getRequestDuration(c) } }
        ),
        202
      );
    }

    // For LOCAL delivery, return CSV content
    return c.json(
      success(
        {
          jobId: result.jobId,
          status: result.status,
          recordCount: result.recordCount,
          filePath: result.filePath,
          csvContent: result.csvContent,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Export failed';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * POST /occ/mileage-feedback
 *
 * Receive actual mileage feedback from OCC system.
 * Validates records and calculates variance statistics.
 *
 * Request Body:
 * - feedback: Array of mileage feedback records
 *   - date: Reading date (YYYY-MM-DD) [required]
 *   - trainNumber: Train identifier [required]
 *   - routeCode: Route operated
 *   - actualKm: Actual kilometers traveled [required]
 *   - scheduledKm: Scheduled kilometers
 *   - variance: Actual - Scheduled (auto-calculated if not provided)
 *   - notes: Optional notes
 *
 * Returns:
 * - 200 OK with processing results and variance summary
 * - 400 Bad Request if all records are invalid
 *
 * @example
 * POST /occ/mileage-feedback
 * {
 *   "feedback": [
 *     {
 *       "date": "2026-01-15",
 *       "trainNumber": "1001",
 *       "routeCode": "NSL",
 *       "actualKm": 520,
 *       "scheduledKm": 500
 *     }
 *   ]
 * }
 */
occRoutes.post('/occ/mileage-feedback', async (c) => {
  const requestId = getRequestId(c);

  try {
    const body = await c.req.json();

    // Validate feedback array
    if (!body.feedback || !Array.isArray(body.feedback)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'feedback array is required', requestId, {
          field: 'feedback',
          expected: 'Array of OCCMileageFeedback objects',
        }),
        400
      );
    }

    if (body.feedback.length === 0) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'feedback array cannot be empty', requestId, {
          field: 'feedback',
        }),
        400
      );
