/**
 * OCC Integration Routes
 *
 * REST endpoints for Operations Control Center integration:
 * - Export run assignments (MMS → OCC)
 * - Receive mileage feedback (OCC → MMS)
 * - Export job history
 *
 * Key endpoints:
 * - POST /occ/export-assignments - Export daily run assignments as CSV
 * - POST /occ/mileage-feedback - Receive actual mileage data from OCC
 * - GET /occ/export-history - List export job history
 * - GET /occ/export/:jobId - Get specific export job status
 * - GET /occ/feedback - Query mileage feedback records
 *
 * @see specs/007-integration.md Section 7.5
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId } from '../middleware/request-context';
import {
  occService,
  type ExportRequest,
  type OCCMileageFeedback,
  type ExportStatus,
} from '../../services/occ';

export const occRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * POST /occ/export-assignments
 *
 * Export run assignments for a given date to OCC CSV format.
 *
 * Request Body:
 * - date: Assignment date (YYYY-MM-DD) [required]
 * - fleetId: Optional fleet filter
 * - deliveryMethod: 'LOCAL' | 'SFTP' | 'REST' (default: LOCAL)
 * - destinationUrl: Required for SFTP/REST delivery
 *
 * Returns:
 * - 200 OK for LOCAL delivery with CSV content
 * - 202 Accepted for SFTP/REST delivery (async)
 * - 400 Bad Request for validation errors
 *
 * @example
 * POST /occ/export-assignments
 * {
 *   "date": "2026-01-15",
 *   "deliveryMethod": "LOCAL"
 * }
 */
occRoutes.post('/occ/export-assignments', async (c) => {
  const requestId = getRequestId(c);

  try {
    const body = await c.req.json();

    // Validate required fields
    if (!body.date) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'date is required', requestId, {
          field: 'date',
          expected: 'YYYY-MM-DD format',
        }),
        400
      );
    }

    // Validate date format
    if (!/^\d{4}-\d{2}-\d{2}$/.test(body.date)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid date format', requestId, {
          field: 'date',
          expected: 'YYYY-MM-DD',
          received: body.date,
        }),
        400
      );
    }

    // Validate delivery method if provided
    const validMethods = ['LOCAL', 'SFTP', 'REST'];
    if (body.deliveryMethod && !validMethods.includes(body.deliveryMethod)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid delivery method', requestId, {
          field: 'deliveryMethod',
          expected: validMethods,
          received: body.deliveryMethod,
        }),
        400
      );
    }

    // Validate destinationUrl for SFTP/REST
    if ((body.deliveryMethod === 'SFTP' || body.deliveryMethod === 'REST') && !body.destinationUrl) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'destinationUrl is required for SFTP/REST delivery', requestId, {
          field: 'destinationUrl',
        }),
        400
      );
    }

    const request: ExportRequest = {
      date: body.date,
      fleetId: body.fleetId,
      deliveryMethod: body.deliveryMethod ?? 'LOCAL',
      destinationUrl: body.destinationUrl,
    };

    const result = await occService.exportRunAssignments(request);

    // For async delivery methods, return 202 Accepted
    if (request.deliveryMethod === 'SFTP' || request.deliveryMethod === 'REST') {
      return c.json(
        success(
          {
            jobId: result.jobId,
            status: result.status,
            recordCount: result.recordCount,
            deliveredAt: result.deliveredAt?.toISOString(),
          },
          requestId
        ),
        202
      );
    }

    // For LOCAL delivery, return CSV content
    return c.json(
      success(
        {
          jobId: result.jobId,
          status: result.status,
          recordCount: result.recordCount,
          filePath: result.filePath,
          csvContent: result.csvContent,
        },
        requestId
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Export failed';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * POST /occ/mileage-feedback
 *
 * Receive actual mileage feedback from OCC system.
 * Validates records and calculates variance statistics.
 *
 * Request Body:
 * - feedback: Array of mileage feedback records
 *   - date: Reading date (YYYY-MM-DD) [required]
 *   - trainNumber: Train identifier [required]
 *   - routeCode: Route operated
 *   - actualKm: Actual kilometers traveled [required]
 *   - scheduledKm: Scheduled kilometers
 *   - variance: Actual - Scheduled (auto-calculated if not provided)
 *   - notes: Optional notes
 *
 * Returns:
 * - 200 OK with processing results and variance summary
 * - 400 Bad Request if all records are invalid
 *
 * @example
 * POST /occ/mileage-feedback
 * {
 *   "feedback": [
 *     {
 *       "date": "2026-01-15",
 *       "trainNumber": "1001",
 *       "routeCode": "NSL",
 *       "actualKm": 520,
 *       "scheduledKm": 500
 *     }
 *   ]
 * }
 */
occRoutes.post('/occ/mileage-feedback', async (c) => {
  const requestId = getRequestId(c);

  try {
    const body = await c.req.json();

    // Validate feedback array
    if (!body.feedback || !Array.isArray(body.feedback)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'feedback array is required', requestId, {
          field: 'feedback',
          expected: 'Array of OCCMileageFeedback objects',
        }),
        400
      );
    }

    if (body.feedback.length === 0) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'feedback array cannot be empty', requestId, {
          field: 'feedback',
        }),
        400
      );
    }

    // Process feedback
    const result = await occService.processMileageFeedback(body.feedback as OCCMileageFeedback[]);

    // If all records are invalid, return 400
    if (result.valid === 0 && result.invalid > 0) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'All feedback records are invalid', requestId, {
          errors: result.errors,
        }),
        400
      );
    }

    return c.json(
      success(
        {
          processed: result.processed,
          valid: result.valid,
          invalid: result.invalid,
          errors: result.errors,
          varianceSummary: result.varianceSummary,
        },
        requestId
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Feedback processing failed';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /occ/export-history
 *
 * List export job history with optional filters.
 *
 * Query Parameters:
 * - fromDate: Filter by export date >= value (YYYY-MM-DD)
 * - toDate: Filter by export date <= value (YYYY-MM-DD)
 * - status: Filter by job status (PENDING, PROCESSING, COMPLETED, FAILED)
 * - limit: Maximum number of results (default: 50)
 *
 * @example
 * GET /occ/export-history?fromDate=2026-01-01&toDate=2026-01-31&status=COMPLETED
 */
occRoutes.get('/occ/export-history', async (c) => {
  const requestId = getRequestId(c);

  try {
    const fromDate = c.req.query('fromDate');
    const toDate = c.req.query('toDate');
    const status = c.req.query('status') as ExportStatus | undefined;
    const limitStr = c.req.query('limit');
    const limit = limitStr ? parseInt(limitStr, 10) : 50;

    // Validate status if provided
    const validStatuses: ExportStatus[] = ['PENDING', 'PROCESSING', 'COMPLETED', 'FAILED'];
    if (status && !validStatuses.includes(status)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid status', requestId, {
          field: 'status',
          expected: validStatuses,
          received: status,
        }),
        400
      );
    }

    const history = await occService.getExportHistory({
      fromDate,
      toDate,
      status,
      limit,
    });

    return c.json(
      success(
        {
          jobs: history.map((job) => ({
            id: job.id,
            exportDate: job.exportDate,
            status: job.status,
            deliveryMethod: job.deliveryMethod,
            recordCount: job.recordCount,
            filePath: job.filePath,
            deliveredAt: job.deliveredAt?.toISOString(),
            errorMessage: job.errorMessage,
            createdAt: job.createdAt.toISOString(),
            completedAt: job.completedAt?.toISOString(),
          })),
          count: history.length,
        },
        requestId
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to retrieve export history';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /occ/export/:jobId
 *
 * Get status of a specific export job.
 *
 * Path Parameters:
 * - jobId: Export job ID
 *
 * Returns:
 * - 200 OK with job details
 * - 404 Not Found if job doesn't exist
 */
occRoutes.get('/occ/export/:jobId', async (c) => {
  const requestId = getRequestId(c);
  const jobId = c.req.param('jobId');

  try {
    const job = await occService.getExportJob(jobId);

    if (!job) {
      return c.json(error(ErrorCodes.NOT_FOUND, 'Export job not found', requestId, { jobId }), 404);
    }

    return c.json(
      success(
        {
          id: job.id,
          exportDate: job.exportDate,
          status: job.status,
          deliveryMethod: job.deliveryMethod,
          recordCount: job.recordCount,
          filePath: job.filePath,
          deliveredAt: job.deliveredAt?.toISOString(),
          errorMessage: job.errorMessage,
          createdAt: job.createdAt.toISOString(),
          completedAt: job.completedAt?.toISOString(),
        },
        requestId
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to retrieve export job';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /occ/feedback
 *
 * Query stored mileage feedback records.
 *
 * Query Parameters:
 * - trainNumber: Filter by train number
 * - fromDate: Filter by date >= value (YYYY-MM-DD)
 * - toDate: Filter by date <= value (YYYY-MM-DD)
 * - minVariance: Filter by |variance| >= value (km)
 *
 * @example
 * GET /occ/feedback?trainNumber=1001&minVariance=50
 */
occRoutes.get('/occ/feedback', async (c) => {
  const requestId = getRequestId(c);

  try {
    const trainNumber = c.req.query('trainNumber');
    const fromDate = c.req.query('fromDate');
    const toDate = c.req.query('toDate');
    const minVarianceStr = c.req.query('minVariance');
    const minVariance = minVarianceStr ? parseFloat(minVarianceStr) : undefined;

    const feedback = await occService.getMileageFeedback({
      trainNumber,
      fromDate,
      toDate,
      minVariance,
    });

    return c.json(
      success(
        {
          feedback,
          count: feedback.length,
        },
        requestId
      ),
      200
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to retrieve feedback';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

/**
 * GET /occ/download/:jobId
 *
 * Download the CSV file for a completed export job.
 *
 * Returns:
 * - 200 OK with CSV content (Content-Type: text/csv)
 * - 404 Not Found if job doesn't exist
 * - 400 Bad Request if job is not completed
 */
occRoutes.get('/occ/download/:jobId', async (c) => {
  const requestId = getRequestId(c);
  const jobId = c.req.param('jobId');

  try {
    const job = await occService.getExportJob(jobId);

    if (!job) {
      return c.json(error(ErrorCodes.NOT_FOUND, 'Export job not found', requestId, { jobId }), 404);
    }

    if (job.status !== 'COMPLETED') {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Export job is not completed', requestId, {
          jobId,
          status: job.status,
        }),
        400
      );
    }

    // For LOCAL delivery method, we would read the file from disk
    // For now, we'll need to re-export to get the content
    // In production, CSV content would be stored or retrieved from file system

    // Re-export to get CSV (simplified approach)
    const result = await occService.exportRunAssignments({
      date: job.exportDate,
      deliveryMethod: 'LOCAL',
    });

    c.header('Content-Type', 'text/csv');
    c.header('Content-Disposition', `attachment; filename="occ_run_assignments_${job.exportDate}.csv"`);

    return c.body(result.csvContent ?? '');
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Download failed';
    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
  }
});

